        const n = parseInt(readLine(), 10);
        const arr = readLine().split(' ').map(Number);

        let isHeap = true;

        for (let j = 0; j < n; j++) {
            const leftChild = 2 * j + 1;
            const rightChild = 2 * j + 2;

            if (leftChild < n && arr[leftChild] < arr[j]) {
                isHeap = false;
                break;
            }

            if (rightChild < n && arr[rightChild] < arr[j]) {
                isHeap = false;
